package com.chrisb97.warehouse.controller;
import com.chrisb97.warehouse.config.AppContext;import com.chrisb97.warehouse.model.*;import com.chrisb97.warehouse.util.DateTimeUtil;import javafx.beans.property.SimpleStringProperty;import javafx.collections.FXCollections;import javafx.fxml.FXML;import javafx.scene.control.*;
public class DashboardController{@FXML private Label productsLabel,totalQuantityLabel,locationsLabel,lowStockLabel;@FXML private TableView<StockMovement> movementsTable;@FXML private TableColumn<StockMovement,String> dateColumn,productColumn,typeColumn,quantityColumn;@FXML private ListView<Product> lowStockList;@FXML public void initialize(){DashboardStats s=AppContext.getInstance().dashboard().stats();productsLabel.setText(String.valueOf(s.activeProducts()));totalQuantityLabel.setText(String.valueOf(s.totalQuantity()));locationsLabel.setText(String.valueOf(s.activeLocations()));lowStockLabel.setText(String.valueOf(s.lowStockProducts()));dateColumn.setCellValueFactory(d->new SimpleStringProperty(DateTimeUtil.format(d.getValue().getCreatedAt())));productColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getProductSku()+" — "+d.getValue().getProductName()));typeColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getMovementType().name()));quantityColumn.setCellValueFactory(d->new SimpleStringProperty(String.valueOf(d.getValue().getQuantity())));movementsTable.setItems(FXCollections.observableArrayList(AppContext.getInstance().dashboard().recentMovements()));lowStockList.setItems(FXCollections.observableArrayList(AppContext.getInstance().dashboard().lowStockProducts()));lowStockList.setCellFactory(v->new ListCell<>(){protected void updateItem(Product p,boolean empty){super.updateItem(p,empty);setText(empty||p==null?null:p.getSku()+" — "+p.getName()+" ("+p.getQuantity()+" / min "+p.getMinimumStock()+")");}});}}
